mapper.select:
SELECT * FROM line_quota


        AND quarter = #{quarter}


        AND production_line = #{productionLine}


        AND part_type = #{partType}


ORDER BY quarter DESC, production_line ASC, part_type ASC

mapper.update:
UPDATE line_quota
SET used_quantity = used_quantity + #{quantity},
    update_time = NOW()
WHERE id = #{id}
  AND max_quantity >= used_quantity + #{quantity}

mapper.select:
SELECT COALESCE(SUM(r.quantity), 0)
FROM stock_out_record r
INNER JOIN small_part p ON r.part_id = p.id
WHERE p.part_type = #{partType}
  AND r.production_line = #{productionLine}
  AND r.create_time >= #{startTime}
  AND r.create_time <= #{endTime}
